module RefModule(
    input clk,
    input reset,
    output reg [3:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset
            q <= 4'b0000;
        end else begin
            // Johnson counter logic
            q <= {q[2:0], ~q[3]};
        end
    end

endmodule
